+    #[test]
+    fn parse_string_with_escaped_quote() {
+        let expr = super::parse_expr(r#"name == 'O\'Brien'"#).unwrap();
+        if let Expr::Compare { right, .. } = expr {
+            assert_eq!(
+                *right,
+                Expr::Literal {
+                    value: Scalar::Utf8("O'Brien".into())
+                }
+            );
+        } else {
+            panic!("expected Compare");
+        }
+    }
+
